import json
# Check articles from March 23-24 for relevant keywords
for day in ['23', '24']:
    try:
        with open(f'articles/2026/03/{day}/articles.jsonl') as f:
            articles = []
            for line in f:
                a = json.loads(line)
                title = (a.get('title') or '').lower()
                content = (a.get('content') or '')[:500].lower()
                if any(kw in title + content for kw in ['aid boat', 'cuba', 'navy search', 'caribbean', '10-day', 'pause', 'trump request', 'kosovo', 'italy playoff']):
                    articles.append((a.get('title',''), a.get('source','')))
        if articles:
            print(f'=== March {day} ===')
            for t, s in articles:
                print(f'  [{s}] {t}')
    except:
        pass
